import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { Container, AppBar, Toolbar, Typography, Button, IconButton, Drawer, List, ListItem, ListItemText, Hidden, CssBaseline } from '@mui/material';
import { ThemeProvider, createTheme } from '@mui/material/styles';
import { LocalizationProvider } from '@mui/x-date-pickers';
import { AdapterDateFns } from '@mui/x-date-pickers/AdapterDateFns';
import MenuIcon from '@mui/icons-material/Menu';
import { Link } from 'react-router-dom';
import Dashboard from './components/Dashboard';
import ItemManagement from './components/ItemManagement';
import CategoryManagement from './components/CategoryManagement';
import PurchaseManagement from './components/PurchaseManagement';
import SaleManagement from './components/SaleManagement';
import BillManagement from './components/BillManagement';
import CompanyManagement from './components/CompanyManagement';
import ExpenseManagement from './components/ExpenseManagement';
import FocManagement from './components/FocManagement';
import ReportManagement from './components/ReportManagement';
import VariantManagement from './components/VariantManagement';
import HistoryManagement from './components/HistoryManagement';

const useStyles = makeStyles((theme) => ({
  root: {
    flexGrow: 1,
  },
  appBar: {
    boxShadow: theme.shadows[4],
  },
  title: {
    flexGrow: 1,
    fontWeight: 'bold',
    letterSpacing: '1px',
  },
  link: {
    color: 'white',
    textDecoration: 'none',
    margin: theme.spacing(1),
    padding: theme.spacing(1),
    borderRadius: theme.shape.borderRadius,
    transition: 'background-color 0.3s, transform 0.2s',
    '&:hover': {
      backgroundColor: 'rgba(255, 255, 255, 0.1)',
      transform: 'scale(1.05)',
    },
  },
  menuButton: {
    marginRight: theme.spacing(2),
  },
  content: {
    marginTop: theme.spacing(10),
    padding: theme.spacing(2),
  },
  drawer: {
    width: 240,
  },
  drawerPaper: {
    width: 240,
    backgroundColor: theme.palette.primary.main,
    color: 'white',
  },
  drawerLink: {
    color: 'white',
    textDecoration: 'none',
  },
}));

// Custom theme for consistent styling
const theme = createTheme({
  palette: {
    primary: {
      main: '#1976d2', // Blue for AppBar and accents
    },
    secondary: {
      main: '#dc004e', // Red for delete buttons, errors
    },
    background: {
      default: '#f5f5f5', // Light background for content
    },
  },
  typography: {
    fontFamily: '"Roboto", "Helvetica", "Arial", sans-serif',
    h4: {
      fontWeight: 600,
    },
    h5: {
      fontWeight: 500,
    },
  },
  shape: {
    borderRadius: 8,
  },
});

const menuItems = [
  { name: 'Dashboard', path: '/' },
  { name: 'Items', path: '/items' },
  { name: 'Variants', path: '/variants' },
  { name: 'Categories', path: '/categories' },
  { name: 'Purchases', path: '/purchases' },
  { name: 'Sales', path: '/sales' },
  { name: 'Bills', path: '/bills' },
  { name: 'Companies', path: '/companies' },
  { name: 'Expenses', path: '/expenses' },
  { name: 'FOC', path: '/focs' },
  { name: 'Reports', path: '/reports' },
  { name: 'History', path: '/history' },
];

function App() {
  const classes = useStyles(theme);
  const [drawerOpen, setDrawerOpen] = useState(false);

  const handleDrawerToggle = () => {
    setDrawerOpen(!drawerOpen);
  };

  const drawer = (
    <div>
      <List>
        {menuItems.map((item) => (
          <ListItem button key={item.name} component={Link} to={item.path} onClick={() => setDrawerOpen(false)}>
            <ListItemText primary={item.name} sx={{ color: 'white' }} />
          </ListItem>
        ))}
      </List>
    </div>
  );

  return (
    <ThemeProvider theme={theme}>
      <LocalizationProvider dateAdapter={AdapterDateFns}>
        <Router>
          <div className={classes.root}>
            <CssBaseline />
            <AppBar position="fixed" className={classes.appBar}>
              <Toolbar>
                <Hidden smUp>
                  <IconButton
                    color="inherit"
                    edge="start"
                    onClick={handleDrawerToggle}
                    className={classes.menuButton}
                  >
                    <MenuIcon />
                  </IconButton>
                </Hidden>
                <Typography variant="h6" className={classes.title}>
                  VISHARA
                </Typography>
                <Hidden xsDown>
                  {menuItems.map((item) => (
                    <Button key={item.name} color="inherit">
                      <Link to={item.path} className={classes.link}>
                        {item.name}
                      </Link>
                    </Button>
                  ))}
                </Hidden>
              </Toolbar>
            </AppBar>
            <Drawer
              className={classes.drawer}
              variant="temporary"
              anchor="left"
              open={drawerOpen}
              onClose={handleDrawerToggle}
              classes={{ paper: classes.drawerPaper }}
              ModalProps={{ keepMounted: true }}
            >
              {drawer}
            </Drawer>
            <Container className={classes.content}>
              <Routes>
                <Route path="/" element={<Dashboard />} />
                <Route path="/items" element={<ItemManagement />} />
                <Route path="/variants" element={<VariantManagement />} />
                <Route path="/categories" element={<CategoryManagement />} />
                <Route path="/purchases" element={<PurchaseManagement />} />
                <Route path="/sales" element={<SaleManagement />} />
                <Route path="/bills" element={<BillManagement />} />
                <Route path="/companies" element={<CompanyManagement />} />
                <Route path="/expenses" element={<ExpenseManagement />} />
                <Route path="/focs" element={<FocManagement />} />
                <Route path="/reports" element={<ReportManagement />} />
                <Route path="/history" element={<HistoryManagement />} />
              </Routes>
            </Container>
          </div>
        </Router>
      </LocalizationProvider>
    </ThemeProvider>
  );
}

export default App;
